function getAllVocab() {
    let allVocab = [];
    for (let category in VOCABULARY) {
        allVocab = allVocab.concat(VOCABULARY[category]);
    }
    return allVocab;
}

function getVocabByCategory(category) {
    return VOCABULARY[category] || [];
}

function getRandomVocab(count = 10) {
    const allVocab = getAllVocab();
    const shuffled = [...allVocab].sort(() => Math.random() - 0.5);
    return shuffled.slice(0, count);
}